import React from 'react'
import ReactApexChart from 'react-apexcharts'
import ApexCharts from 'apexcharts'
import './styles.css'

var pointCount = 10000

// Seeded PRNG (mulberry32) so the two clusters are identical on every reload
// and, crucially, identical across the SVG and canvas benchmark runs: the
// comparison is over the same scene, not two different random ones.
function makeRng(seed) {
  return function () {
    seed |= 0
    seed = (seed + 0x6d2b79f5) | 0
    var t = Math.imul(seed ^ (seed >>> 15), 1 | seed)
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296
  }
}

// Box-Muller gaussian off the seeded stream: two legible clusters at any
// density, so the plotted shape stays readable from 1k to 100k points.
function generateClusters(count) {
  var rng = makeRng(0x513a7a)
  function gauss(mean, sd) {
    var u = 1 - rng()
    var v = rng()
    return mean + sd * Math.sqrt(-2 * Math.log(u)) * Math.cos(2 * Math.PI * v)
  }
  var half = Math.floor(count / 2)
  var a = new Array(half)
  var b = new Array(count - half)
  for (var i = 0; i < a.length; i++) {
    a[i] = [+gauss(32, 9).toFixed(2), +gauss(62, 15).toFixed(2)]
  }
  for (var j = 0; j < b.length; j++) {
    b[j] = [+gauss(70, 10).toFixed(2), +gauss(34, 13).toFixed(2)]
  }
  return [a, b]
}

var clusters = generateClusters(pointCount)

// Every SVG mark is a live DOM node, so counting nodes inside the chart makes
// the hybrid renderer visible: canvas keeps this in the dozens no matter how
// many points are plotted.
function strataNodeCount() {
  var el = document.querySelector('#chart')
  return el ? el.getElementsByTagName('*').length : 0
}

// Stateless console helpers (no chart/options refs), shared by the vanilla,
// React and Vue builds so each per-format script only holds the chart wiring.
function selected(segId) {
  var pressed = document
    .getElementById(segId)
    .querySelector('button[aria-pressed="true"]')
  return pressed || document.getElementById(segId).querySelector('button')
}

function setPressed(segId, btn) {
  var seg = document.getElementById(segId)
  Array.prototype.forEach.call(seg.querySelectorAll('button'), function (b) {
    b.setAttribute('aria-pressed', b === btn ? 'true' : 'false')
  })
}

function rendererPill(mode) {
  var cls = mode === 'canvas' ? 'canvas' : 'svg'
  return (
    '<span class="strata-pill ' +
    cls +
    '"><span class="dot"></span>' +
    mode +
    '</span>'
  )
}

function setMeter(id, value, max) {
  var pct = max > 0 ? Math.max(2, Math.round((value / max) * 100)) : 0
  document.getElementById(id).style.width = pct + '%'
}

function showComparison(out) {
  document.getElementById('strataBarsEmpty').hidden = true
  document.getElementById('strataBarsData').hidden = false

  var maxTime = Math.max(out.svg.ms, out.canvas.ms, 1)
  setMeter('tSvg', out.svg.ms, maxTime)
  setMeter('tCan', out.canvas.ms, maxTime)
  document.getElementById('tSvgN').textContent = out.svg.ms + ' ms'
  document.getElementById('tCanN').textContent = out.canvas.ms + ' ms'

  var maxNodes = Math.max(out.svg.nodes, out.canvas.nodes, 1)
  setMeter('nSvg', out.svg.nodes, maxNodes)
  setMeter('nCan', out.canvas.nodes, maxNodes)
  document.getElementById('nSvgN').textContent = out.svg.nodes.toLocaleString()
  document.getElementById('nCanN').textContent =
    out.canvas.nodes.toLocaleString()

  var speedup =
    out.canvas.ms > 0 ? (out.svg.ms / out.canvas.ms).toFixed(1) : '-'
  var nodeCut =
    out.canvas.nodes > 0 ? Math.round(out.svg.nodes / out.canvas.nodes) : '-'
  document.getElementById('strataVerdict').innerHTML =
    'At ' +
    pointCount.toLocaleString() +
    ' points, canvas rendered <b>' +
    speedup +
    '&times; faster</b> with about <b>' +
    nodeCut +
    '&times; fewer</b> DOM nodes on this device.'
}

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [
      { name: 'Cluster A', data: clusters[0] },
      { name: 'Cluster B', data: clusters[1] },
    ],
    options: {
      chart: {
        height: 400,
        type: 'scatter',
        renderer: 'auto',
        rendererThreshold: 8000,
        animations: { enabled: false },
        zoom: { enabled: true, type: 'xy' },
        toolbar: { autoSelected: 'zoom' },
        fontFamily: 'Helvetica, Arial, sans-serif',
      },
      markers: { size: 3, strokeWidth: 0 },
      colors: ['#0891b2', '#f59e0b'],
      grid: { borderColor: '#e7ecf5' },
      legend: { position: 'top' },
      xaxis: {
        type: 'numeric',
        tickAmount: 10,
        labels: {
          formatter: function (val) {
            return parseFloat(val).toFixed(0)
          },
        },
      },
      yaxis: {
        tickAmount: 8,
        labels: {
          formatter: function (val) {
            return val.toFixed(0)
          },
        },
      },
      tooltip: { shared: false, intersect: true },
    },
  })

  React.useEffect(() => {
    // Strata drives its own chart lifecycle (destroy + rebuild per renderer), so
    // this build skips the react-apexcharts wrapper and creates the instance in
    // #chart directly, exactly like the vanilla build. pointCount, clusters,
    // generateClusters, strataNodeCount and the DOM helpers (selected, setPressed,
    // rendererPill, setMeter, showComparison) live in the shared head script.
    const busy = document.getElementById('strataBusy')
    const elRenderer = document.getElementById('mRenderer')
    const elTime = document.getElementById('mTime')
    const elNodes = document.getElementById('mNodes')
    const elPoints = document.getElementById('mPoints')
    let lastRenderMs = 0
    let chart = null
    let disposed = false

    // The vanilla build gets a mutable `options` global from the template; rebuild
    // it here from the parsed chart state.
    const options = Object.assign({ series: state.series }, state.options)
    options.chart = Object.assign({}, state.options.chart)

    function updateMetrics() {
      if (!chart || !chart.w) return
      const active =
        typeof chart.getActiveRenderer === 'function'
          ? chart.getActiveRenderer()
          : 'svg'
      elRenderer.innerHTML = rendererPill(active)
      elTime.innerHTML =
        (lastRenderMs > 0 ? lastRenderMs : '-') + '<small>ms</small>'
      elNodes.textContent = strataNodeCount().toLocaleString()
      elPoints.textContent = pointCount.toLocaleString()
    }

    // Build a fresh instance in the #chart container with a forced renderer,
    // returning the render time and resulting DOM-node count.
    function renderWith(mode) {
      if (disposed) return Promise.resolve({ ms: 0, nodes: 0 })
      options.chart.renderer = mode
      options.series = [
        { name: 'Cluster A', data: clusters[0] },
        { name: 'Cluster B', data: clusters[1] },
      ]
      const t = performance.now()
      if (chart) chart.destroy()
      chart = new ApexCharts(document.querySelector('#chart'), options)
      return chart.render().then(function () {
        return {
          ms: Math.round(performance.now() - t),
          nodes: strataNodeCount(),
        }
      })
    }

    function rebuild() {
      pointCount = parseInt(selected('strataCount').getAttribute('data-n'), 10)
      const mode = selected('strataMode').getAttribute('data-m')
      clusters = generateClusters(pointCount)
      busy.classList.add('on')
      return renderWith(mode).then(function (r) {
        lastRenderMs = r.ms
        busy.classList.remove('on')
        updateMetrics()
      })
    }

    function benchmarkBoth() {
      pointCount = parseInt(selected('strataCount').getAttribute('data-n'), 10)
      clusters = generateClusters(pointCount)
      const currentMode = selected('strataMode').getAttribute('data-m')
      const benchBtn = document.getElementById('strataBench')
      const renderBtn = document.getElementById('strataRender')
      benchBtn.disabled = true
      renderBtn.disabled = true
      busy.classList.add('on')

      const out = {}
      // Render SVG, then canvas, then restore the user's selected renderer.
      // Chained so the two heavy renders never overlap.
      renderWith('svg')
        .then(function (r) {
          out.svg = r
          return renderWith('canvas')
        })
        .then(function (r) {
          out.canvas = r
          return renderWith(currentMode)
        })
        .then(function () {
          if (disposed) return
          lastRenderMs = currentMode === 'svg' ? out.svg.ms : out.canvas.ms
          showComparison(out)
          busy.classList.remove('on')
          benchBtn.disabled = false
          renderBtn.disabled = false
          updateMetrics()
        })
    }

    // Wire the segmented buttons: pressing one just marks it selected (no render
    // until Render / Benchmark), matching a console feel.
    ;['strataCount', 'strataMode'].forEach(function (segId) {
      document.getElementById(segId).addEventListener('click', function (e) {
        const btn = e.target.closest('button')
        if (btn) setPressed(segId, btn)
      })
    })

    document.getElementById('strataRender').addEventListener('click', rebuild)
    document
      .getElementById('strataBench')
      .addEventListener('click', benchmarkBoth)

    // Initial render into #chart, then seed the readout.
    chart = new ApexCharts(document.querySelector('#chart'), options)
    chart.render().then(updateMetrics)

    return () => {
      disposed = true
      if (chart) chart.destroy()
    }
  }, [])

  return (
    <div>
      <div className="strata">
        <p className="strata-lede">
          Every SVG mark is a live DOM node, so a 50k-point scatter is roughly
          100k nodes: slow to build and slow to restyle on hover. <b>Strata</b>{' '}
          keeps that DOM for the chart chrome but paints the dense series into a
          single
          <code>&lt;canvas&gt;</code>. Crank the points and flip the renderer to
          feel the difference.
        </p>

        <section className="strata-console" aria-label="Renderer benchmark">
          <div className="strata-controls">
            <div className="strata-ctl">
              <span className="strata-ctl-label">Points</span>
              <div
                className="strata-seg"
                id="strataCount"
                role="group"
                aria-label="Point count"
              >
                <button type="button" data-n="1000">
                  1k
                </button>
                <button type="button" data-n="10000" aria-pressed="true">
                  10k
                </button>
                <button type="button" data-n="50000">
                  50k
                </button>
                <button type="button" data-n="100000">
                  100k
                </button>
              </div>
            </div>
            <div className="strata-ctl">
              <span className="strata-ctl-label">Renderer</span>
              <div
                className="strata-seg"
                id="strataMode"
                role="group"
                aria-label="Renderer mode"
              >
                <button type="button" data-m="auto" aria-pressed="true">
                  auto
                </button>
                <button type="button" data-m="svg">
                  svg
                </button>
                <button type="button" data-m="canvas">
                  canvas
                </button>
              </div>
            </div>
            <div className="strata-run">
              <button
                className="strata-btn ghost"
                id="strataBench"
                type="button"
              >
                Benchmark both
              </button>
              <button
                className="strata-btn primary"
                id="strataRender"
                type="button"
              >
                Render
              </button>
            </div>
          </div>

          <div className="strata-readout">
            <div className="strata-metric">
              <div className="k">Active renderer</div>
              <div className="v renderer" id="mRenderer">
                <span className="strata-pill canvas">
                  <span className="dot"></span>canvas
                </span>
              </div>
            </div>
            <div className="strata-metric">
              <div className="k">Render time</div>
              <div className="v trace" id="mTime">
                -<small>ms</small>
              </div>
            </div>
            <div className="strata-metric">
              <div className="k">DOM nodes in chart</div>
              <div className="v" id="mNodes">
                -
              </div>
            </div>
            <div className="strata-metric">
              <div className="k">Points plotted</div>
              <div className="v" id="mPoints">
                -
              </div>
            </div>
          </div>

          <div className="strata-stage">
            <div className="strata-hint">
              Scatter &middot; two clusters &middot; zoom and pan with the
              toolbar; the canvas layer stays smooth where SVG would stutter.
            </div>
            <div id="chart"></div>
            <div className="strata-busy" id="strataBusy">
              rendering&hellip;
            </div>
          </div>
        </section>

        <section className="strata-compare">
          <h2>Head to head &middot; same data, both renderers</h2>
          <p className="strata-empty" id="strataBarsEmpty">
            Press <b>Benchmark both</b> to render the current dataset once as
            SVG and once as canvas, and compare.
          </p>
          <div id="strataBarsData" hidden>
            <div className="strata-barrow">
              <span className="strata-rlabel">Render time</span>
              <div className="strata-track">
                <div className="strata-lane svg">
                  <span className="strata-who">
                    <span className="dot"></span>SVG
                  </span>
                  <div className="strata-meter">
                    <span id="tSvg"></span>
                  </div>
                  <span className="strata-num" id="tSvgN"></span>
                </div>
                <div className="strata-lane canvas">
                  <span className="strata-who">
                    <span className="dot"></span>Canvas
                  </span>
                  <div className="strata-meter">
                    <span id="tCan"></span>
                  </div>
                  <span className="strata-num" id="tCanN"></span>
                </div>
              </div>
            </div>
            <div className="strata-barrow">
              <span className="strata-rlabel">DOM nodes</span>
              <div className="strata-track">
                <div className="strata-lane svg">
                  <span className="strata-who">
                    <span className="dot"></span>SVG
                  </span>
                  <div className="strata-meter">
                    <span id="nSvg"></span>
                  </div>
                  <span className="strata-num" id="nSvgN"></span>
                </div>
                <div className="strata-lane canvas">
                  <span className="strata-who">
                    <span className="dot"></span>Canvas
                  </span>
                  <div className="strata-meter">
                    <span id="nCan"></span>
                  </div>
                  <span className="strata-num" id="nCanN"></span>
                </div>
              </div>
            </div>
            <p className="strata-verdict" id="strataVerdict"></p>
          </div>
        </section>

        <section className="strata-notes">
          <div className="strata-note">
            <h3>
              <span className="n">01</span>Opt in, one line
            </h3>
            <p>
              Set <code>chart.renderer: 'auto'</code> and Strata switches to
              canvas once the mark count crosses <code>rendererThreshold</code>.
              Below it, output is identical SVG.
            </p>
          </div>
          <div className="strata-note">
            <h3>
              <span className="n">02</span>Hybrid, not a rewrite
            </h3>
            <p>
              Only the series paths and markers move to canvas. Axes, gridlines,
              crosshairs, tooltips and annotations stay real SVG: crisp text,
              native events, SVG export.
            </p>
          </div>
          <div className="strata-note">
            <h3>
              <span className="n">03</span>Tree shakeable
            </h3>
            <p>
              The interface and SVG adapter are core. The canvas backend is a
              separate feature,{' '}
              <code>import 'apexcharts/features/renderer-canvas'</code>, that
              shakes out when unused.
            </p>
          </div>
        </section>
      </div>
    </div>
  )
}

export default ApexChart

