  border-radius: 4px;
}
@media (max-width: 560px) {
  .strata-readout {
    grid-template-columns: repeat(2, 1fr);
  }
  .strata-metric:nth-child(2n) {
    border-right: 0;
  }
  .strata-metric:nth-child(-n + 2) {
    border-bottom: 1px solid #dce3f0;
  }
  .strata-notes {
    grid-template-columns: 1fr;
  }
  .strata-run {
    margin-left: 0;
    width: 100%;
  }
  .strata-run .strata-btn {
    flex: 1;
  }
}
@media (prefers-reduced-motion: reduce) {
  .strata-meter > span {
    transition: none;
  }
}
